### Sorting a List of Objects in Python

```python
class Person:
    def __init__(self, name, age):
        self.name = name
        self.age = age

    def __repr__(self):
        return f'Person(name={self.name}, age={self.age})'

    def __eq__(self, other):
        return self.name == other.name and self.age == other.age

    def __lt__(self, other):
        return self.age < other.age

people = [
    Person('John', 30),
    Person('Alice', 25),
    Person('Bob', 40)
]

# Sorting by 'name'
sorted_by_name = sorted(people, key=lambda x: x.name)
print(sorted_by_name)

# Sorting by 'age' in ascending order
sorted_by_age_ascending = sorted(people, key=lambda x: x.age)
print(sorted_by_age_ascending)

# Sorting by 'age' in descending order
sorted_by_age_descending = sorted(people, key=lambda x: x.age, reverse=True)
print(sorted_by_age_descending)
```

