### Sort List of Objects by Attribute

```python
class Person:
    def __init__(self, name, age):
        self.name = name
        self.age = age

people = [Person('John', 30), Person('Alice', 25), Person('Bob', 35)]

# 1. Sort in-place (mutates original list)
def sort_by_age_ascending(lst):
    try:
        lst.sort(key=lambda x: x.age)
    except AttributeError:
        print("Error: List contains objects that do not have 'age' attribute.")
    except TypeError:
        print("Error: List contains non-scalar values.")

def sort_by_age_descending(lst):
    try:
        lst.sort(key=lambda x: x.age, reverse=True)
    except AttributeError:
        print("Error: List contains objects that do not have 'age' attribute.")
    except TypeError:
        print("Error: List contains non-scalar values.")

# 2. Create a new sorted list (does not mutate original)
def sorted_copy_by_age(lst, ascending=True):
    try:
        return sorted(lst, key=lambda x: x.age, reverse=not ascending)
    except AttributeError:
        print("Error: List contains objects that do not have 'age' attribute.")
    except TypeError:
        print("Error: List contains non-scalar values.")

# Usage
print("In-place sorting:")
sort_by_age_ascending(people[:])  # Use a copy of the original list
print("Sorted list:", people)

print("\nSorted copy:")
sorted_list = sorted_copy_by_age(people)
print("Sorted list:", sorted_list)
```

### Key Points:

- Use the built-in `sort()` method or the `sorted()` function to sort lists of objects.
- Provide a `key` function (lambda in this example) to specify the attribute that determines the sort order.
- Implement robust error handling for `AttributeError` and `TypeError` to handle non-compliant objects.
- Consider using `ascending` or `reverse` parameters to control the sort order.

